var Dashboard=function(){var _K="vincipher_client_token";function _gt(){return localStorage.getItem(_K)}function _st(k){localStorage.setItem(_K,k)}function _ct(){localStorage.removeItem(_K)}function _hd(){return{"X-Api-Key":_gt(),"Content-Type":"application/json"}}function _x(s){var d=document.createElement("div");d.textContent=s;return d.innerHTML}function _fd(i){return new Date(i).toLocaleString("fr-FR",{day:"numeric",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"})}function _ts(m){var el=document.getElementById("toast");el.textContent=m;el.classList.add("visible");setTimeout(function(){el.classList.remove("visible")},3e3)}var _pg=1,_sz=20;async function _li(e){e.preventDefault();document.getElementById("loginError").textContent="";var tk=document.getElementById("loginToken").value.trim();if(!tk){document.getElementById("loginError").textContent="Cl\u00e9 API requise.";return!1}try{var r=await fetch("/api/Playground/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({token:tk})}),d=await r.json();if(!r.ok){document.getElementById("loginError").textContent=d.error||"Cl\u00e9 invalide ou expir\u00e9e.";return!1}_st(tk);_show(d)}catch(ex){document.getElementById("loginError").textContent="Erreur r\u00e9seau."}return!1}function _lo(){_ct();location.reload()}function _show(u){document.getElementById("loginScreen").classList.add("hidden");document.getElementById("mainApp").classList.remove("hidden");document.getElementById("userBadge").textContent=u.name||u.email||"Client";_lss()}async function _init(){if(!_gt())return;try{var r=await fetch("/api/Playground/me",{headers:_hd()});if(r.ok){var d=await r.json();_show(d)}else{_ct()}}catch(ex){_ct()}}function _swt(t){document.querySelectorAll(".tab").forEach(function(e){e.classList.toggle("active",e.dataset.tab===t)});["decode","history","tokens","account"].forEach(function(id){var el=document.getElementById("tab-"+id);if(el)el.classList.toggle("hidden",id!==t)});if(t==="history")_lh(_pg);if(t==="tokens")_ltk();if(t==="account")_lac()}async function _lss(){var r=await fetch("/api/Playground/me/stats",{headers:_hd()});if(!r.ok)return;var s=await r.json();var rate=s.successRate??0;var rc=rate>=90?"good":rate>=70?"warn":"bad";var remTxt=s.remainingToday<0?"\u221e":s.remainingToday;var limTxt=s.dailyLimit>0?s.dailyLimit+"/j":"\u221e";document.getElementById("statsGrid").innerHTML='<div class="stat-card"><div class="stat-value">'+s.totalRequests+'</div><div class="stat-label">Total requ\u00eates</div></div>'+'<div class="stat-card"><div class="stat-value">'+s.todayRequests+'</div><div class="stat-label">Aujourd\u2019hui</div></div>'+'<div class="stat-card"><div class="stat-value">'+remTxt+'</div><div class="stat-label">Restant ('+limTxt+')</div></div>'+'<div class="stat-card good"><div class="stat-value">'+s.successCount+'</div><div class="stat-label">Succ\u00e8s</div></div>'+'<div class="stat-card bad"><div class="stat-value">'+s.failureCount+'</div><div class="stat-label">\u00c9checs</div></div>'+'<div class="stat-card '+rc+'"><div class="stat-value">'+rate+'%</div><div class="stat-label">Taux de succ\u00e8s</div></div>'+'<div class="stat-card"><div class="stat-value">'+Math.round(s.avgResponseTimeMs)+'ms</div><div class="stat-label">Temps moyen</div></div>'+'<div class="stat-card"><div class="stat-value">'+s.activeTokens+'</div><div class="stat-label">Cl\u00e9s actives</div></div>'}async function _dec(e){e.preventDefault();var vin=document.getElementById("decodeVin").value.trim().toUpperCase();if(!vin||vin.length!==17)return!1;var st=document.getElementById("decodeStatus"),rs=document.getElementById("decodeResult"),btn=document.getElementById("decodeBtn");st.innerHTML='<span style="color:var(--muted)">D\u00e9codage de <strong>'+_x(vin)+"</strong>\u2026</span>";rs.classList.add("hidden");btn.disabled=true;try{var r=await fetch("/api/Playground/full-decode?vin="+encodeURIComponent(vin),{headers:_hd()});var d=await r.json();if(!r.ok){st.innerHTML='<span style="color:var(--red)">'+(d.error||d.message||"Erreur "+r.status)+"</span>";if(d.remaining!==undefined)st.innerHTML+='<br><span style="color:var(--dim);font-size:12px">'+d.todayCount+"/"+d.dailyLimit+" requ\u00eates utilis\u00e9es aujourd\u2019hui</span>";btn.disabled=false;return!1}var meta={};var specs={};for(var k in d){if(k.startsWith("_")){meta[k]=d[k]}else{specs[k]=d[k]}}var remaining=meta["_remaining"]||"?";var ms=meta["_responseTimeMs"]||"?";var limit=meta["_dailyLimit"]||"?";st.innerHTML='<span style="color:var(--green)">\u2713 D\u00e9cod\u00e9 en '+ms+'ms</span> <span style="color:var(--dim);font-size:12px">\u2014 '+remaining+" restant"+(limit!=="0"?" sur "+limit+"/jour":"")+"</span>";var h='<div class="decode-result-panel"><div class="decode-result-header"><div class="decode-result-title">'+(specs.make?_x(specs.make):"V\u00e9hicule")+(specs.model?" "+_x(specs.model):"")+(specs.model_year?" ("+_x(specs.model_year)+")":"")+'</div><div class="decode-result-vin mono">'+_x(vin)+"</div></div>"+'<div class="decode-specs-grid">';var labels={"make":"Marque","model":"Mod\u00e8le","model_year":"Ann\u00e9e","trim_level":"Finition","body_style":"Carrosserie","body_type":"Type","fuel_type":"Carburant","transmission":"Transmission","manufactured_in":"Fabriqu\u00e9 \u00e0","manufacturer":"Constructeur","country":"Pays","number_of_doors":"Portes","number_of_seats":"Si\u00e8ges","displacement_si":"Cylindr\u00e9e (cc)","displacement_nominal":"Cylindr\u00e9e (L)","engine_cylinders":"Cylindres","engine_horse_power":"Puissance (ch)","engine_kilo_watts":"Puissance (kW)","engine_head":"Architecture","engine_aspiration":"Aspiration","engine_valves":"Soupapes","manual_gearbox":"Bo\u00eete manuelle","driveline":"Transmission","vehicule_type":"Type v\u00e9hicule","region":"R\u00e9gion","displacement_cid":"Cylindr\u00e9e (cid)"};for(var key in specs){var label=labels[key]||key.replace(/_/g," ");h+='<div class="decode-spec"><div class="decode-spec-label">'+_x(label)+'</div><div class="decode-spec-value">'+_x(specs[key])+"</div></div>"}h+="</div></div>";rs.innerHTML=h;rs.classList.remove("hidden");_lss()}catch(ex){st.innerHTML='<span style="color:var(--red)">Erreur r\u00e9seau.</span>'}btn.disabled=false;return!1}async function _lh(page){_pg=page;var r=await fetch("/api/Playground/me/history?page="+page+"&size="+_sz,{headers:_hd()});if(!r.ok)return;var d=await r.json();document.getElementById("historyCount").textContent=d.total+" requ\u00eate"+(d.total>1?"s":"");var tp=Math.ceil(d.total/_sz)||1;var pgHtml="";if(tp>1){pgHtml+='<button '+(page<=1?"disabled":"")+" onclick=\"Dashboard.history("+(page-1)+')">\u2190</button>';for(var i=1;i<=tp&&i<=7;i++){pgHtml+='<button class="'+(i===page?"active":"")+'" onclick="Dashboard.history('+i+')">'+i+"</button>"}if(tp>7)pgHtml+='<button disabled>\u2026</button><button onclick="Dashboard.history('+tp+')">'+tp+"</button>";pgHtml+='<button '+(page>=tp?"disabled":"")+" onclick=\"Dashboard.history("+(page+1)+')">\u2192</button>'}document.getElementById("historyPagination").innerHTML=pgHtml;if(!d.logs.length){document.getElementById("historyList").innerHTML='<p style="color:var(--dim);text-align:center;padding:40px">Aucune requ\u00eate enregistr\u00e9e.</p>';return}document.getElementById("historyList").innerHTML='<div class="table-wrap"><table><thead><tr><th>VIN</th><th>Statut</th><th>R\u00e9sultat</th><th>Temps</th><th>Date</th></tr></thead><tbody>'+d.logs.map(function(l){return'<tr><td class="mono" style="cursor:pointer;text-decoration:underline" onclick="document.getElementById(\'decodeVin\').value=\''+_x(l.vin)+'\';Dashboard.switchTab(\'decode\')">'+_x(l.vin)+'</td><td><span style="color:'+(l.success?"var(--green)":"var(--red)")+'">'+l.statusCode+'</span></td><td style="color:'+(l.success?"var(--green)":"var(--red)")+'">'+(l.success?"\u2713 Succ\u00e8s":"\u2717 \u00c9chec")+"</td><td>"+l.responseTimeMs+"ms</td><td>"+_fd(l.timestamp)+"</td></tr>"}).join("")+"</tbody></table></div>"}async function _ltk(){var r=await fetch("/api/Playground/me",{headers:_hd()});if(!r.ok)return;var d=await r.json();if(!d.tokens||!d.tokens.length){document.getElementById("tokensList").innerHTML='<p style="color:var(--dim);text-align:center;padding:40px">Aucune cl\u00e9.</p>';return}document.getElementById("tokensList").innerHTML='<div class="section-title">Mes cl\u00e9s API</div>'+d.tokens.map(function(t){var ex=new Date(t.expiresAt)<new Date(),st=!t.active?"revoked":ex?"expired":"active",sl=st==="active"?"Actif":st==="expired"?"Expir\u00e9":"R\u00e9voqu\u00e9",sc=st==="active"?"status-active":st==="expired"?"status-expired":"status-revoked";var lim=t.dailyLimit>0?t.dailyLimit+"/jour":"\u221e";return'<div class="token-card"><div><div class="token-key">'+_x(t.key)+"</div><div style=\"font-size:12px;color:var(--dim);margin-top:4px\">"+_x(t.name)+' \u2022 Limite : '+lim+'</div></div><div class="token-meta"><span class="'+sc+'">'+sl+"</span><br>Expire : "+_fd(t.expiresAt)+"</div></div>"}).join("")}async function _lac(){var r=await fetch("/api/Playground/me",{headers:_hd()});if(!r.ok)return;var d=await r.json();document.getElementById("accountInfo").innerHTML='<div class="section-title" style="margin-top:0">Mon compte</div>'+'<div class="detail-row"><span>Nom</span><span>'+_x(d.name)+'</span></div>'+'<div class="detail-row"><span>Email</span><span class="mono">'+_x(d.email)+'</span></div>'+'<div class="detail-row"><span>T\u00e9l\u00e9phone</span><span>'+_x(d.phone||"\u2014")+'</span></div>'+'<div class="detail-row"><span>Domaine</span><span>'+_x(d.domain||"\u2014")+'</span></div>'+'<div class="detail-row"><span>Membre depuis</span><span>'+_fd(d.createdAt)+"</span></div>"}_init();return{login:_li,logout:_lo,switchTab:_swt,history:_lh,decode:_dec}}();
